180→    private static void requestPostsForFeed(final long feedId,
181→                                            final UpdateAction updateAction,
182→                                            final ReaderActions.UpdateResultListener resultListener) {
183→        String path = "read/feed/" + feedId + "/posts/?meta=site,likes";
184→        if (updateAction == UpdateAction.REQUEST_OLDER) {
185→            String dateOldest = ReaderPostTable.getOldestPubDateInFeed(feedId);
186→            if (!TextUtils.isEmpty(dateOldest)) {
187→                path += "&before=" + UrlUtils.urlEncode(dateOldest);
188→            }
189→        }
190→
191→        com.wordpress.rest.RestRequest.Listener listener = new RestRequest.Listener() {
192→            @Override
193→            public void onResponse(JSONObject jsonObject) {
194→                handleUpdatePostsResponse(null, jsonObject, updateAction, resultListener);
195→            }
196→        };
197→        RestRequest.ErrorListener errorListener = new RestRequest.ErrorListener() {
198→            @Override
199→            public void onErrorResponse(VolleyError volleyError) {
200→                AppLog.e(AppLog.T.READER, volleyError);
201→                resultListener.onUpdateResult(ReaderActions.UpdateResult.FAILED);
202→            }
203→        };
204→
205→        AppLog.d(AppLog.T.READER, "updating posts in feed " + feedId);
206→        WordPress.getRestClientUtilsV1_2().get(path, null, null, listener, errorListener);
207→    }
