290→    /*
291→     * returns the endpoint to use when requesting posts with the passed tag
292→     */
293→    private static String getRelativeEndpointForTag(ReaderTag tag) {
294→        if (tag == null) {
295→            return null;
296→        }
297→
298→        // if passed tag has an assigned endpoint, return it and be done
299→        if (!TextUtils.isEmpty(tag.getEndpoint())) {
300→            return getRelativeEndpoint(tag.getEndpoint());
301→        }
302→
303→        // check the db for the endpoint
304→        String endpoint = ReaderTagTable.getEndpointForTag(tag);
305→        if (!TextUtils.isEmpty(endpoint)) {
306→            return getRelativeEndpoint(endpoint);
307→        }
308→
309→        // never hand craft the endpoint for default tags, since these MUST be updated
310→        // using their stored endpoints
311→        if (tag.tagType == ReaderTagType.DEFAULT) {
312→            return null;
313→        }
314→        return formatRelativeEndpointForTag(tag.getTagSlug());
315→    }
316→
317→    private static String formatRelativeEndpointForTag(@NonNull final String tagSlug) {
318→        return String.format("read/tags/%s/posts", ReaderUtils.sanitizeWithDashes(tagSlug));
319→    }
320→
321→    public static String formatFullEndpointForTag(@NonNull final String tagSlug) {
322→        return WordPress.getRestClientUtilsV1_2().getRestClient().getEndpointURL()
323→               + formatRelativeEndpointForTag(tagSlug);
324→    }
325→
326→    /*
327→     * returns the passed endpoint without the unnecessary path - this is
328→     * needed because as of 20-Feb-2015 the /read/menu/ call returns the
329→     * full path but we don't want to use the full path since it may change
330→     * between API versions (as it did when we moved from v1 to v1.1)
331→     *
332→     * ex: https://public-api.wordpress.com/rest/v1/read/tags/fitness/posts
333→     * becomes just read/tags/fitness/posts
334→     */
335→    private static String getRelativeEndpoint(final String endpoint) {
336→        if (endpoint != null && endpoint.startsWith("http")) {
337→            int pos = endpoint.indexOf("/read/");
338→            if (pos > -1) {
339→                return endpoint.substring(pos + 1, endpoint.length());
340→            }
341→            pos = endpoint.indexOf("/v1/");
342→            if (pos > -1) {
343→                return endpoint.substring(pos + 4, endpoint.length());
344→            }
345→        }
346→        return StringUtils.notNullStr(endpoint);
347→    }
348→}
