321→    public static String formatFullEndpointForTag(@NonNull final String tagSlug) {
322→        return WordPress.getRestClientUtilsV1_2().getRestClient().getEndpointURL()
323→               + formatRelativeEndpointForTag(tagSlug);
324→    }
